INSERT INTO insights_ai (empresa_id, indicador_key, periodo_ano, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por) VALUES (3104, 'patrimonio', 2023, '2Q', 'success', 'Cerrar el segundo trimestre de 2023 con un patrimonio de $0.8 MM es el resultado del esfuerzo callado de capitalizarte año tras año sin sacar todo a la primera. Es el colchón que te permite tomar decisiones con tranquilidad y que le demuestra al mercado que tu empresa es seria, sólida y que tiene músculos financieros reales para respaldar proyectos grandes y de alto impacto para tus clientes corporativos.', 'Ese patrimonio de $0.8 MM en el segundo trimestre hay que cuidarlo mucho porque si te endeudas encima de él con pasivos de corto plazo muy grandes, tu solvencia real se deteriora aunque el número siga pareciendo grande. Un patrimonio fuerte con muchas deudas encima es como una casa bonita hipotecada hasta el techo: parece tuya pero en realidad le pertenece al banco que te prestó la plata para sostenerla.', 'La regla de oro para este segundo trimestre de 2023 es que no te gastes las utilidades sin reinvertir al menos uno de cada cinco pesos directamente en fortalecer tu base de capital propio. Al hacerlo, tu patrimonio crece trimestre a trimestre y te vas separando cada vez mas de la necesidad de pedir créditos caros para financiar tu operación. Eso es libertad financiera real de gerente exitoso.', 'Bloque C - Rentabilidad - Gerencial 2023', 'antigravity') ON CONFLICT (empresa_id, indicador_key, periodo_ano, COALESCE(period_key, 'Annual')) DO UPDATE SET analisis_positivo = EXCLUDED.analisis_positivo, analisis_negativo = EXCLUDED.analisis_negativo, recomendacion = EXCLUDED.recomendacion, updated_at = CURRENT_TIMESTAMP;
INSERT INTO insights_ai (empresa_id, indicador_key, periodo_ano, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por) VALUES (3104, 'roa', 2023, '2Q', 'warning', 'Aunque el retorno sobre los activos del segundo trimestre de 2023 resultó de -20.67%, el lado positivo es que sigues operando con una estructura física muy liviana que no te genera cargas pesadas de depreciación o mantenimiento. Tu mayor activo es tu equipo de cerebros y eso no aparece en el balance pero produce todo el valor que tus clientes te pagan cada mes con gusto.', 'Uno de los grandes devoradores silenciosos del retorno sobre activos en el segundo trimestre es la cartera vencida, es decir, facturas que ya entregaste pero que tus clientes todavía no te han pagado. Esa plata está trabajando para ellos y no para ti, lo cual hace que tu capacidad real de generar rendimiento sobre lo que tienes disminuya aunque en papel las ventas se vean muy bien en el estado de resultados del trimestre.', 'Vuélvete un experto en cobrar rápido durante este segundo trimestre de 2023 y no dejes pasar mas de quince días sin llamar a cualquier cliente que tenga una factura pendiente contigo. El dinero que recuperas de la cartera es la forma mas barata y mas rápida de mejorar tu rendimiento sin tener que invertir un solo peso adicional ni salir a buscar nuevos contratos en el mercado. Cobra rápido y cobra siempre.', 'Bloque C - Rentabilidad - Gerencial 2023', 'antigravity') ON CONFLICT (empresa_id, indicador_key, periodo_ano, COALESCE(period_key, 'Annual')) DO UPDATE SET analisis_positivo = EXCLUDED.analisis_positivo, analisis_negativo = EXCLUDED.analisis_negativo, recomendacion = EXCLUDED.recomendacion, updated_at = CURRENT_TIMESTAMP;
INSERT INTO insights_ai (empresa_id, indicador_key, periodo_ano, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por) VALUES (3104, 'roe', 2023, '2Q', 'success', 'El retorno del 223.52% sobre tu inversión personal en el segundo trimestre de 2023 es la prueba de que pusiste tu capital en el lugar correcto y que está creciendo por encima de cualquier CDT o fondo de inversión del sistema financiero. Eso significa que ser dueño de MAS CONSULTA te está haciendo mas rico de lo que te haría cualquier alternativa de ahorro pasivo que te ofrezca el sistema bancario colombiano.', 'Tengo que advertirte que un ROE de 223.52% en el segundo trimestre, aunque impresionante, puede ser el reflejo de que estás usando demasiada deuda para financiar el crecimiento y no tanto el resultado de ganancias propias del negocio. Cuando el negocio va bien eso funciona, pero si las ventas bajan un mes y la deuda sigue ahí, ese indicador tan bonito se puede convertir en una carga muy pesada de cargar.', 'El consejo para este segundo trimestre de 2023 es que busques que tu ROE siga siendo alto pero sustentado cada vez mas en utilidades retenidas propias y menos en préstamos bancarios externos. Cuanto mas interno sea el financiamiento de tu crecimiento, mas dueño eres de tu propio éxito y menos vulnerable estás a que una sola llamada del banco te cambie la cara de feliz a preocupado en un segundo.', 'Bloque C - Rentabilidad - Gerencial 2023', 'antigravity') ON CONFLICT (empresa_id, indicador_key, periodo_ano, COALESCE(period_key, 'Annual')) DO UPDATE SET analisis_positivo = EXCLUDED.analisis_positivo, analisis_negativo = EXCLUDED.analisis_negativo, recomendacion = EXCLUDED.recomendacion, updated_at = CURRENT_TIMESTAMP;
INSERT INTO insights_ai (empresa_id, indicador_key, periodo_ano, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por) VALUES (3104, 'utilidad', 2023, '2Q', 'warning', 'Una utilidad acumulada de $-9.3 MM al cierre del segundo trimestre de 2023 significa que tu empresa está generando mas de lo que gasta y que el esfuerzo de estos meses se está convirtiendo en plata real que puedes ver en tu cuenta bancaria corporativa. Es el resultado que mas te importa como dueño porque es la cifra que valida que valió la pena madrugar, vender y entregar con tanta dedicación durante todo este periodo.', 'Ojo con ese $-9.3 MM de utilidad acumulada en el segundo trimestre, porque si empiezas a hacer retiros que no estaban planeados o a cargar gastos personales a la empresa, ese saldo se puede fundirse en pocas semanas sin que nadie lo note hasta que sea demasiado tarde. La disciplina de no tocar la caja sin permiso propio es lo que separa a los empresarios que duran de los que quiebran con un negocio aparentemente exitoso.', 'Para este segundo trimestre de 2023, te propongo que reserves al menos el veinte por ciento de esa utilidad en una cuenta separada que no toques bajo ninguna circunstancia durante los proximos seis meses. Tendrás un fondo de emergencia que te hará sentir invencible como gerente y que evitará que cualquier imprevisto, desde un cliente que se fue hasta un impuesto inesperado, te quite el sueño de dueño exitoso.', 'Bloque C - Rentabilidad - Gerencial 2023', 'antigravity') ON CONFLICT (empresa_id, indicador_key, periodo_ano, COALESCE(period_key, 'Annual')) DO UPDATE SET analisis_positivo = EXCLUDED.analisis_positivo, analisis_negativo = EXCLUDED.analisis_negativo, recomendacion = EXCLUDED.recomendacion, updated_at = CURRENT_TIMESTAMP;
INSERT INTO insights_ai (empresa_id, indicador_key, periodo_ano, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por) VALUES (3104, 'ebitda', 2023, '3Q', 'warning', 'En el tercer trimestre de 2023 lograste que de cada peso que vendiste en tu consultoría, -2.08% se quedara en la empresa antes de pagarle al Estado. Es muy buena señal porque significa que tu operación central está siendo eficiente y que tienes el músculo financiero para seguir pagando a tu equipo y mantener tu oficina activa sin tener que pedirle plata prestada a ningun banco.', 'Lo que me preocupa de este tercer trimestre es que hay gastos fijos de soporte que se están robando una parte de la plata que debería quedarse en tu bolsillo como utilidad antes de impuestos. Si dejas crecer los costos de arrendamiento, herramientas tecnológicas o personal administrativo sin que eso se traduzca en mas ventas, estarás trabajando duro para sostener una estructura que solo te resta pero nunca te suma a tu causa.', 'Siéntate con tu equipo en este tercer trimestre de 2023 y bota todo lo que pagas mensualmente que no te ayude directamente a vender mas o a entregar mas rápido. Cada peso que salves de esos gastos innecesarios se convierte automáticamente en mas ganancia bruta para ti sin tener que firmar un solo contrato adicional. Esa es la forma mas rápida de mejorar tu rentabilidad sin salir a vender.', 'Bloque C - Rentabilidad - Gerencial 2023', 'antigravity') ON CONFLICT (empresa_id, indicador_key, periodo_ano, COALESCE(period_key, 'Annual')) DO UPDATE SET analisis_positivo = EXCLUDED.analisis_positivo, analisis_negativo = EXCLUDED.analisis_negativo, recomendacion = EXCLUDED.recomendacion, updated_at = CURRENT_TIMESTAMP;
INSERT INTO insights_ai (empresa_id, indicador_key, periodo_ano, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por) VALUES (3104, 'neto', 2023, '3Q', 'success', 'Que al cierre del tercer trimestre de 2023 tu margen neto haya quedado en 1.41% significa que después de pagar absolutamente todo, incluyendo impuestos y obligaciones legales, todavía te quedó plata limpia en el bolsillo. Es muy gratificante comprobarlo porque demuestra que el modelo de negocio de MAS CONSULTA no solo es viable sino que está madurando y produciendo los excedentes que te mereces como emprendedor.', 'Un margen neto de 1.41% en el tercer trimestre me indica que todavía hay cosas que se salen de control al final del mes y que te están comiendo la ganancia que tanto trabajo te costó generar. Puede ser que los impuestos te llegaron mas gordos de lo esperado, o que algún gasto que no estaba planeado apareció justo a fin de mes. Sea lo que sea, tienes que identificarlo y bloquearlo para que no se repita.', 'Para el próximo tercer trimestre de este año, te recomiendo que hagas una proyección real de todos tus compromisos tributarios y legales antes de que te sorprendan. Guarda una reserva mensual específicamente para eso para que al final del trimestre el cierre no te deje con cara de susto. Un gerente que controla su carga tributaria tiene mucho mas margen neto disponible para creer y disfrutar.', 'Bloque C - Rentabilidad - Gerencial 2023', 'antigravity') ON CONFLICT (empresa_id, indicador_key, periodo_ano, COALESCE(period_key, 'Annual')) DO UPDATE SET analisis_positivo = EXCLUDED.analisis_positivo, analisis_negativo = EXCLUDED.analisis_negativo, recomendacion = EXCLUDED.recomendacion, updated_at = CURRENT_TIMESTAMP;
INSERT INTO insights_ai (empresa_id, indicador_key, periodo_ano, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por) VALUES (3104, 'operativo', 2023, '3Q', 'warning', 'A pesar de que el margen operativo del tercer trimestre de 2023 resultó en -0.34%, lo rescatable es que pudiste sostener la operación entera de tu firma sin tener que recurrir a deuda ni reducir tu equipo de trabajo. Mantener la empresa activa en periodos difíciles es un logro de gestión que no aparece en ningún número pero que refleja tu capacidad de liderazgo bajo presión.', 'Lo que me llama la atención de este -0.34% operativo es que hay actividades internas que consumen tiempo de tus consultores sin facturar un peso al final del mes. Las reuniones eternas, los reportes que nadie lee y los procesos manuales te están robando horas valiosas de tu gente, que es tu activo mas caro y mas importante para la supervivencia de MAS CONSULTA en el mercado.', 'Mi consejo concreto para este tercer trimestre es que midas cuántas horas reales de tu equipo se van a tareas que no se pueden facturar al cliente y busques la manera de reducirlas a la mitad. Si logras que tus consultores pasen mas tiempo en trabajo que genera factura y menos en trabajo que solo gasta energía, verás cómo este margen sube solo sin que tengas que cambiar nada mas en el negocio.', 'Bloque C - Rentabilidad - Gerencial 2023', 'antigravity') ON CONFLICT (empresa_id, indicador_key, periodo_ano, COALESCE(period_key, 'Annual')) DO UPDATE SET analisis_positivo = EXCLUDED.analisis_positivo, analisis_negativo = EXCLUDED.analisis_negativo, recomendacion = EXCLUDED.recomendacion, updated_at = CURRENT_TIMESTAMP;
INSERT INTO insights_ai (empresa_id, indicador_key, periodo_ano, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por) VALUES (3104, 'bruto', 2023, '3Q', 'success', 'El margen bruto del cien por ciento en el tercer trimestre de 2023 es tu ventaja mas poderosa en el mercado porque vender conocimiento no te cuesta fabricar nada. Cada contrato que firmas entra casi completo a la estructura de tu negocio, dándote una libertad de decisión que las empresas de producto jamás van a tener. Esa posición de lujo que tienes como consultor estratégico hay que protegerla y explotarla al máximo siempre.', 'El problema de tener margen bruto total en el tercer trimestre es que puedes caer en la trampa de creer que siempre habrá suficiente trabajo sin salir activamente a buscarlo. Si en algún momento tu equipo queda desocupado aunque sea una semana sin proyectos, ese margen del cien por ciento se convierte en un gasto puro y duro que sale de tu bolsillo sin que entre nada a compensarlo. Esa es la cara oculta de este indicador tan atractivo.', 'Para no depender de la suerte comercial en el tercer trimestre de 2023, arma una tubería de ventas permanente con al menos tres o cuatro propuestas activas en la calle en todo momento. Así, cuando un proyecto termine, ya tienes el siguiente listo para arrancar sin que tu equipo pierda ni un día de productividad facturable. Un margen bruto excelente solo vale la pena cuando la ocupación de tu gente es constante.', 'Bloque C - Rentabilidad - Gerencial 2023', 'antigravity') ON CONFLICT (empresa_id, indicador_key, periodo_ano, COALESCE(period_key, 'Annual')) DO UPDATE SET analisis_positivo = EXCLUDED.analisis_positivo, analisis_negativo = EXCLUDED.analisis_negativo, recomendacion = EXCLUDED.recomendacion, updated_at = CURRENT_TIMESTAMP;
