INSERT INTO insights_ai (empresa_id, indicador_key, periodo_ano, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por) VALUES (3104, 'operativo', 2024, '1Q', 'success', 'En el primer trimestre de 2024 cerraste con un margen operativo de 64.11%, lo que me dice que estás gestionando muy bien los gastos del día a día de tu firma de consultoría sin desperdiciar dinero en cosas que no tienen retorno. Es la prueba de que sabes cómo manejar la empresa con cabeza fría y que tu equipo está siendo productivo dentro del presupuesto que les asignaste para operar.', 'Lo que me llama la atención de este 64.11% operativo es que hay actividades internas que consumen tiempo de tus consultores sin facturar un peso al final del mes. Las reuniones eternas, los reportes que nadie lee y los procesos manuales te están robando horas valiosas de tu gente, que es tu activo mas caro y mas importante para la supervivencia de MAS CONSULTA en el mercado.', 'Mi consejo concreto para este primer trimestre es que midas cuántas horas reales de tu equipo se van a tareas que no se pueden facturar al cliente y busques la manera de reducirlas a la mitad. Si logras que tus consultores pasen mas tiempo en trabajo que genera factura y menos en trabajo que solo gasta energía, verás cómo este margen sube solo sin que tengas que cambiar nada mas en el negocio.', 'Bloque C - Rentabilidad - Gerencial 2024', 'antigravity') ON CONFLICT (empresa_id, indicador_key, periodo_ano, COALESCE(period_key, 'Annual')) DO UPDATE SET analisis_positivo = EXCLUDED.analisis_positivo, analisis_negativo = EXCLUDED.analisis_negativo, recomendacion = EXCLUDED.recomendacion, updated_at = CURRENT_TIMESTAMP;
