INSERT INTO insights_ai (empresa_id, indicador_key, periodo_ano, period_key, tipo, analisis_positivo, analisis_negativo, recomendacion, metodologia, generado_por) VALUES (3104, 'roa', 2025, '1Q', 'warning', 'Aunque el retorno sobre los activos del primer trimestre de 2025 resultó de -0.28%, el lado positivo es que sigues operando con una estructura física muy liviana que no te genera cargas pesadas de depreciación o mantenimiento. Tu mayor activo es tu equipo de cerebros y eso no aparece en el balance pero produce todo el valor que tus clientes te pagan cada mes con gusto.', 'Uno de los grandes devoradores silenciosos del retorno sobre activos en el primer trimestre es la cartera vencida, es decir, facturas que ya entregaste pero que tus clientes todavía no te han pagado. Esa plata está trabajando para ellos y no para ti, lo cual hace que tu capacidad real de generar rendimiento sobre lo que tienes disminuya aunque en papel las ventas se vean muy bien en el estado de resultados del trimestre.', 'Vuélvete un experto en cobrar rápido durante este primer trimestre de 2025 y no dejes pasar mas de quince días sin llamar a cualquier cliente que tenga una factura pendiente contigo. El dinero que recuperas de la cartera es la forma mas barata y mas rápida de mejorar tu rendimiento sin tener que invertir un solo peso adicional ni salir a buscar nuevos contratos en el mercado. Cobra rápido y cobra siempre.', 'Bloque C - Rentabilidad - Gerencial 2025', 'antigravity') ON CONFLICT (empresa_id, indicador_key, periodo_ano, COALESCE(period_key, 'Annual')) DO UPDATE SET analisis_positivo = EXCLUDED.analisis_positivo, analisis_negativo = EXCLUDED.analisis_negativo, recomendacion = EXCLUDED.recomendacion, updated_at = CURRENT_TIMESTAMP;
